  public Room createRoom(String name, String description, User user) {
    Room room = new Room();
    room.setName(name);
    room.setDescription(description);
    room.setOwner(user);
    return roomRepository.save(room);
  }

  public Room getRoom(String roomId) {
    return roomRepository.findOne(roomId);
  }

  public Room updateRoom(String roomId, String name, String description) {
    Room room = roomRepository.findOne(roomId);
    room.setName(name);
    room.setDescription(description);
    return roomRepository.save(room);
  }

  public void deleteRoom(String roomId) {
    roomRepository.delete(roomId);
  }

  public List<Room> getRooms(User user) {
    return roomRepository.findByOwner(user);
