		double powerConsumption = 0;
		for (int i = 0; i < this.powerMeasurements.size(); i++) {
			if (start == null || this.powerMeasurements.get(i).getTimestamp().after(start)) {
				if (end == null || this.powerMeasurements.get(i).getTimestamp().before(end)) {
					powerConsumption += this.powerMeasurements.get(i).getPowerConsumption();
				}
			}
		}
		return powerConsumption / this.powerMeasurements.size();
	}

