	public static boolean isItemInInventory(Player player, int itemId) {
		for (int i = 0; i < player.getInventory().getItems().length; i++) {
			if (player.getInventory().getItems()[i]!= null) {
				if (player.getInventory().getItems()[i].getId() == itemId) {
					return true;
				}
			}
		}
		return false;
	}

