		for (int i = 0; i < player.getEquipment().getItems().length; i++) {
			if (player.getEquipment().getItems()[i]!= null) {
				if (player.getEquipment().getItems()[i].getId() == itemId) {
					return true;
				}
			}
		}
		return false;
	}

